  .progressbar {
      counter-reset: step;
  }
  .progressbar li {
      list-style: none;
      display: inline-block;
      width: 15%;
      position: relative;
      text-align: center;
      cursor: pointer;
  }
  .progressbar li:before {
      content: counter(step);
      counter-increment: step;
      /*width: 40px;*/
      height: 10px;
      line-height : 0px;
      border: 2px solid #ECECEC;
      border-radius: 5px;
      display: block;
      text-align: center;
      margin: 0 auto 10px auto;
      background-color: #ECECEC;
      font-size: 0px;
  }
  .progressbar li:after {
      content: "";
      position: absolute;
      width: 100%;
      height: 0px;
      background-color: transparent;
      top: 15px;
      left: -50%;
      z-index : -1;
  }
  .progressbar li:first-child:after {
      content: none;
  }
  .progressbar li.active {
      /*color: green;*/
      /*background-color: #02E196;*/
  }
  .progressbar li.active:before {
      border-color: #02E196;
      background-color: #02E196;
  } 
  .progressbar li.active + li:after {
      background-color: green;
  }

