    /* The actual timeline (the vertical ruler) */
    .timeline {
      position: relative;
      max-width: 1200px;
      margin: 0 auto;
    }

    /* The actual timeline (the vertical ruler) */
    .timeline::after {
      content: '';
      position: absolute;
      width: 0px;
      background-color: #F0F0F0;
      top: 0;
      bottom: 0;
      left: 30%;
      margin-left: -3px;
    }

    .timeline > li > .timeline-badge {
        left: 30%;
        top: -10px;
    }

    .timeline:before {
        left: 30%;
    }

    .timeline > li > .timeline-panel {
        width: 60%;
        top: -30px;
        right: 2%;
    }

    .timeline > li > .timeline-panel:before {
        display: none;
    }

    .timeline > li > .timeline-panel:after {
        display: none;
    }

    .timeline > li > .timeline-panel.panelday {
        width: 70%;
        padding: 0px;
        top: -12px;
        right: 0;
    }

    .time {
        padding-left: 50px;
