<script src="<?php echo site_url('assets/socket.io/socket.io.js'); ?>"></script>

<script>
    $(document).ready(function(){

        var agentid = '<? echo USERID?>';
        var socket = io.connect('https://moaioc.moai-crm.com:3001',{
            'reconnection': true,
            'reconnectionDelay': 500,
            'reconnectionAttempts': 10,
            'secure' : true
        });
        
        socket.on('connect',function() {
            console.log('Client has connected to the servervv!');
        });

        socket.on('reconnect', function(e){
            console.log('reconnect :'+ e);
        });

        socket.emit('joinRoomAgent',{agentid: agentid});

        socket.on('RightBarData', function(data){
            $('#module').val(data.module);
            $('#crmid').val(data.parentid);

            $("#defaultOpen").removeClass("active");
            $("#relatedbnt").removeClass("active");

            $("#defaultOpen").addClass("active");
            $('#related').css('display','none');
            RightBarChange();

        });

        $('.tags').tagsinput({
            maxTags: 10,
        });

        $("#sale_startdate").change(function(){
            // alert("The text has been changed.");
            var salestartdate = $('#sale_startdate').val();

            $('#sale_enddate').val(salestartdate);
        });


    });

