    $(".shot_case").on('click', function () { 
        $("#loader-wrapper").fadeIn('slow');
        var crmid = $('#crmid').val();
        var accountname = $('#accountname').val();
        var mobileaccount = $('#mobileaccount').val();
        var emailaccount = $('#email1account').val();
        var villageaccount = $('#villageaccount').val();//อาคาร/หมู่บ้าน
        var addresslineaccount = $('#addresslineaccount').val();//ห้องเลขที่ / ชั้นที่
        var addressline1account = $('#addressline1account').val();//เลขที่
        var villagenoaccount = $('#villagenoaccount').val();//หมู่
        var laneaccount = $('#laneaccount').val();//ตรอก
        var streetaccount = $('#streetaccount').val();//ถนน
        var subdistrictaccount = $('#subdistrictaccount').val();//ตำบล/แขวง
        var districtaccount = $('#districtaccount').val();//อำเภอ/เขต
        var provinceaccount = $('#provinceaccount').val();//จังหวัด
        var postalcodeaccount = $('#postalcodeaccount').val();//รหัสไปรษณีย์
        var erpaccountidaccount = $('#erpaccountidaccount').val();//รหัสลูกค้า SAP

        var address = '';

