            address = address+addressline1account+' ';
        }
        if(addresslineaccount != ''){
            address = address+addresslineaccount+' ';
        }
        if(villageaccount != ''){
            address = address+villageaccount+' ';
        }
        if(villagenoaccount != ''){
            address = address+villagenoaccount+' ';
        }
