    $(".shot_visit").on('click', function () { 
        $("#loader-wrapper").fadeIn('slow');

        var crmid = $('#crmid').val();
        var accountname = $('#accountname').val();
        var idcardnoaccount = $('#idcardnoaccount').val();
        var mobileaccount = $('#mobileaccount').val();

        $('#accountidsale').val(crmid);
