    $("#relatedbnt").on('click', function () { 
        
        $('#tagtab').empty();
        $('#cardcase').empty();
        $('#cardsalesvisit').empty();
        $('#carddeal').empty();
        $('#cardnote').empty();
        $('#cardvoucher').empty();

        var modulename = $("#module").val();
        var crmid = $("#crmid").val();

        // console.log(crmid);
        $("#loader-wrapper").fadeIn('slow');

        var url = "<?php echo site_url('omnichannel/getrelate'); ?>";
        var data = [];

        $.ajax(url, {
            type: "POST",
            data: data + "&crmid=" + crmid + "&module=" + modulename,
            success: function (data) {
                var result = jQuery.parseJSON(data);
                // console.log(result.data);

                $.each(result.data, function( index, value ) {

                    // console.log(value.module);
                    if (value.module == "Tag") {
                        // console.log(value.total);
                        $('#totaltag').text(value.total);
                        $('.tabtag').css('display','block');

                        $.each(value.relateList, function(index,value){
                            var i = $('<i />',{ class:'fa fa-times' }).click(function(){
                                $.removeTab(value.id)
                            });
                            var a = $('<a />').attr({ 'data-tabkey':value.id, 'href':'javascript:void(0)'}).html(value.name);
                            $(a).append(i);

                            var li = $('<li class="'+value.id+'"/>').append(a);

                            $("#tagtab").append(li);

                        });
                    }else if(value.module == "Sales Visit") {
                        $('.tabsalesvisit').css('display','block');

                        // console.log(value.total);

                        $('#totalsalesvisit').text(value.total);

                        $.each(value.relateList, function(index,value){
                            // console.log(value);
                            //cardsalesvisit
                            var d_start = new Date(value.startdate);
                            var dd = String(d_start.getDate()).padStart(2, '0');
                            var mm = String(d_start.getMonth() + 1).padStart(2, '0'); //January is 0!
                            var yyyy = d_start.getFullYear();

                            var datestart = mm + '-' + dd + '-' + yyyy;
                            var color = '#018FFB'
                            if(value.status == 'Plan'){
                                color = "#018FFB";
                            }else if(value.status == 'Complete'){
                                color = "#00E296";
