        $('#paymentcaseshow').val('');
        $('#installmentpaymentcaseshow').val('');
        $('#totalcaseshow').val('');
        $('#cashiercaseshow').val('');
        $('#branchcaseshow').val('');
        $('#case_dateshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
