        $('#date_of_executionshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
        $('#executiontimecaseshow').val('');
        $('#date_completedshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
        $('#timecompletedcaseshow').val('');
        $('#date_incompleteshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
        $('#timeincompletecaseshow').val('');
        $('#date_cancelledshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
        $('#timecancelledcaseshow').val('');

        $.post(site_url('omnichannel/getcase'), {crmid: id}, function (rs) { 
            $('#ticket_noshowcase').val(rs.data[0].ticket_no);
            $('#case_statusshowcase').val(rs.data[0].case_status).trigger('change');
            $('#ticket_titlcaseshow').val(rs.data[0].title);
