            $('#duedatecaseshow').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(rs.data[0].duedate));
            $('#paymentcaseshow').val(rs.data[0].payment);
            $('#installmentpaymentcaseshow').val(rs.data[0].installment_payment);
            $('#totalcaseshow').val(rs.data[0].total);
            $('#cashiercaseshow').val(rs.data[0].cashier);
            $('#branchcaseshow').val(rs.data[0].branch);
            
            $('#case_dateshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(rs.data[0].case_date));
            $('#case_timeshow').val(rs.data[0].case_time);
            $('#date_of_executionshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(rs.data[0].date_of_execution));
            $('#executiontimecaseshow').val(rs.data[0].execution_time);
            $('#date_completedshowcase').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(rs.data[0].date_completed));
            $('#timecompletedcaseshow').val(rs.data[0].time_completed);
