    function previewsalesvisit(id) {
        
        $("#loader-wrapper-full").fadeIn('slow');

        $('#activitytypeshowsale').val("").trigger('change');
        $('#sale_startdateshow').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
        $('#sale_timestartshow').val('');
        $('#sale_enddateshowsale').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
        $('#sale_endtimeshow').val('');
        $('#eventstatusshowsale').val("").trigger('change');
        $('#branchsaleshow').val('').trigger('change');
        $('#officershowsale').val('');
        $('#accountidshowsale').val('');
        $('#accountnameshowsale').val('');
        $('#phoneshowsale').val('');
        $('#idcardnoshow').val('');
        $('#questionnairenameshow').val('');
        $('#scoringshow').val("").trigger('change');
        $('#scoringresultshow').val("").trigger('change');
        $('#googlelinksalesshow').val('');
        $('#descriptionsalesshow').val('');
        $('#commentplansalesshow').val('');
        $('#sale_remarkshow').val('');
        $('#sale_reportsalesvisit').val('');

        $.post(site_url('omnichannel/getsalevisit'), {crmid: id}, function (rs) { 
            
            if (rs.data[0].activitytype == "ออดิท") {
                $('#activitytypeshowsale').val("ออดิท").trigger('change');
            } else if (rs.data[0].activitytype == "เครดิตสกอริ่ง") {
                $('#activitytypeshowsale').val("เครดิตสกอริ่ง").trigger('change');
            } else if (rs.data[0].activitytype == "อื่นๆ") {
                $('#activitytypeshowsale').val("อื่นๆ").trigger('change');
            } else {
                $('#activitytypeshowsale').val("").trigger('change');
            }
      
            $('#sale_startdateshow').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(rs.data[0].date_start));
            $('#sale_timestartshow').val(rs.data[0].time_start);
            $('#sale_enddateshowsale').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(rs.data[0].due_date));
            $('#sale_endtimeshow').val(rs.data[0].time_end);

            if (rs.data[0].eventstatus == "Plan") {
                $('#eventstatusshowsale').val("Plan").trigger('change');
            } else if (rs.data[0].eventstatus == "Complete") {
                $('#eventstatusshowsale').val("Complete").trigger('change');
            } else if (rs.data[0].eventstatus == "Cancel") {
                $('#eventstatusshowsale').val("Cancel").trigger('change');
            } else {
                $('#eventstatusshowsale').val("").trigger('change');
            }

            $('#branchsaleshow').val(rs.data[0].branch).trigger('change');
            $('#officershowsale').val(rs.data[0].officer);
            $('#accountidshowsale').val(rs.data[0].accountid);
            $('#accountnameshowsale').val(rs.data[0].accountname);
            $('#phoneshowsale').val(rs.data[0].phone);
            $('#idcardnoshow').val(rs.data[0].idcardno);
            $('#questionnairenameshow').val(rs.data[0].questionnaire_name);

            if (rs.data[0].scoring == "เครดิตเช่าซื้อ") {
                $('#scoringshow').val("เครดิตเช่าซื้อ").trigger('change');
            } else if (rs.data[0].scoring == "เครดิตจำนำทะเบียน") {
                $('#scoringshow').val("เครดิตจำนำทะเบียน").trigger('change');
            } else {
                $('#scoringshow').val("").trigger('change');
            }

            if (rs.data[0].scoringresult == "ผ่าน") {
                $('#scoringresultshow').val("ผ่าน").trigger('change');
            } else if (rs.data[0].scoringresult == "ไม่ผ่าน") {
                $('#scoringresultshow').val("ไม่ผ่าน").trigger('change');
            } else {
                $('#scoringresultshow').val("").trigger('change');
            }
            $('#googlelinksalesshow').val(rs.data[0].googlelink);
            $('#descriptionsalesshow').val(rs.data[0].description);
            $('#commentplansalesshow').val(rs.data[0].commentplan);
            $('#sale_remarkshow').val(rs.data[0].sale_remark);
            $('#sale_reportsalesvisit').val(rs.data[0].sale_report);

            $("#loader-wrapper-full").fadeOut('slow');

        },'json');

    }

