    $.removeTab = function(id){
        
        var crmid = $('#crmid').val();
        var modulename = $('#module').val();

        var url = "<?php echo site_url('omnichannel/delete_tag'); ?>";
        var data = [];
        
        $("#loader-wrapper").fadeIn('slow');

        $.ajax(url, {
            type: "POST",
            data: data + "&relation_id=" + crmid + "&id=" + id + "&relation_module=" + modulename,
            success: function (data) {
                var result = jQuery.parseJSON(data);
                //console.log(result);
                if (result["Type"] == "S") {
                    
                    swal({
                        position: "center", //'top-end',
                        type: "success",
                        title: result["Message"],
                        showConfirmButton: false,
                        timer: 2000,
                    });
                    var totaltag = parseInt($('#totaltag').text(),10);
                    var count = totaltag-1;
                    $('#totaltag').text(count);

                    $('#myModalTag').modal('hide');
                    $('#tagtab li.'+id).remove();
                    //$('#tagtab li').remove();
                    var crmid = $('#crmid').val();
                    var modulename = $('#module').val();
                    
                    $("#loader-wrapper").fadeOut('slow');

                } else {
                    swal("", result["Message"], "error");
                    $("#loader-wrapper").fadeOut('slow');
                }
            },
            error: function (data) {
                console.log("error");
                $("#loader-wrapper").fadeOut('slow');
            },
        });
    }

