    function savetag() {
        
        var counttag = $('ul#tagtab li').length;
        var name = $('#tagsname').val();
        var crmid = $('#crmid').val();
        var modulename = $('#module').val();
        if(name == '' || name == null){
            $('.bootstrap-tagsinput').css('border','1px solid red'); //border: 1px solid red
            return false;
        }
        $('.bootstrap-tagsinput').css('border','1px solid #ccc'); //border: 1px solid #ccc;
        var a_name = name.split(",");
        var newtag = a_name.length;
        var sumtag = counttag+newtag;
        
        if(sumtag > 10){
            $('.tag-error').show();
            return false;
        }
        var url = "<?php echo site_url('omnichannel/create_tag'); ?>";
        var data = [];
        
        $("#loader-wrapper-full").fadeIn('slow');

        $.ajax(url, {
            type: "POST",
            data: data + "&relation_id=" + crmid + "&name=" + name + "&relation_module=" + modulename,
            success: function (data) {
                var result = jQuery.parseJSON(data);
                
                if (result["Type"] == "S") {

                    swal({
                        position: "center", //'top-end',
                        type: "success",
                        title: result["Message"],
                        showConfirmButton: false,
                        timer: 2000,
                    });

                    $('#totaltag').text(sumtag);

                    $('#myModalTag').modal('hide');

                    
                    $.each(result.data, function( key, value ) {
                        var i = $('<i />',{ class:'fa fa-times' }).click(function(){
                            $.removeTab(value.tagid)
                        });
                            var a = $('<a />').attr({ 'data-tabkey':value.tagid, 'href':'javascript:void(0)'}).html(value.name);
                        $(a).append(i);

                        var li = $('<li class="'+value.tagid+'"/>').append(a);

                        $("#tagtab").append(li);
                    });

                    $('#tagsname').tagsinput('removeAll');

                    $('#totaltag').text(sumtag);
                    /*$.post(site_url('omnichannel/getrelate'), {crmid: crmid, module: modulename}, function (rs) { 
                        //console.log(rs);
                        $.each(rs.data, function( index, value ) {
                            if (value.module == "Tag") {
                                $('#totaltag').text(value.total);
                            } 
                        });
                    },'json');*/
                    $("#loader-wrapper-full").fadeOut('slow');
                } else {
                    swal("", result["Message"], "error");
                    $("#loader-wrapper-full").fadeOut('slow');
                }
            },
            error: function (data) {
                console.log("error");
                $("#loader-wrapper-full").fadeOut('slow');
            },
        });
    }


