    function updateleads() {
        var form = $( "#form_save_lead" );
        form.validate();

        if (form.valid() == false) {
            //console.log('false');
            alert("กรุณากรอกข้อมูลให้ครบ");
            return false;
        }else {
            $("#loader-wrapper").fadeIn('slow');

            var crmid = $("#crmid").val();
            var leadid = $("#leadid").val();

            if (crmid != null) {

                $('#dealnamelead').valid();

                var url = "<?php echo site_url('omnichannel/update_lead'); ?>";
                var data = $('#form_save_lead').serialize();

                    $.ajax(url, {
                    type: "POST",
                    data: data + "&crmid=" + crmid + "&leadid=" + leadid,
                    success: function (data) {
                        var result = jQuery.parseJSON(data);
                        //console.log(result);
                        if (result["Type"] == "S") {

                            $("#check").css('display','block');
                            $("#savelead").css('display','none');

                            setTimeout(function(){ 
                                $("#check").css('display','none');
                                $("#savelead").css('display','block');
                            }, 3000);
                            $("#loader-wrapper").fadeOut('slow');
                        } else {
                            swal("", result["Message"], "error");
                            $("#loader-wrapper").fadeOut('slow');
                        }
                    },
                    error: function (data) {
                        console.log("error");
                        $("#loader-wrapper").fadeOut('slow');
                    },
                });
            }

        }
    }

