    function savejob() {
        
        var url = "<?php echo site_url('omnichannel/create_job'); ?>";
        var data = $("#form_save_job").serialize();
        $("#loader-wrapper").fadeIn('slow');
        $.ajax(url, {
            type: "POST",
            data: data,
            success: function (data) {
                var result = jQuery.parseJSON(data);
                console.log(result);
                if (result["Type"] == "S") {
                    
                    swal({
                        position: "center", //'top-end',
                        type: "success",
                        title: result["Message"],
                        showConfirmButton: false,
                        timer: 2000,
                    });

                    $('.cardJob').css('display','block');
                    $('#crmidjob').val(result.data.Crmid);

                    $.post(site_url('omnichannel/getjob'), {crmid: result.data.Crmid}, function (rs) { 
                       
                        console.log(rs);

                        $('#cardjobdate').text(rs.data[0].jobdate);
                        $('#cardjobtime').text(rs.data[0].notification_time);
                        $('#cardjobemail').text(rs.data[0].contact_email);

                        $('#jobnameshow').val(rs.data[0].job_name);

                        if (rs.data[0].job_status == "Open") {
                            $('#jobstatusshow').val("Open").trigger('change');
                        } else if (rs.data[0].job_status == "Pending") {
                            $('#jobstatusshow').val("Pending").trigger('change');
                        } else if (rs.data[0].job_status == "Closed") {
                            $('#jobstatusshow').val("Closed").trigger('change');
                        } else {
                            $('#jobstatusshow').val("Cancelled").trigger('change');
                        }

                        $('#jobdateshow').val(rs.data[0].jobdate);
                        $('#notificationtimeshow').val(rs.data[0].notification_time);
                        $('#jobdateoperateshow').val(rs.data[0].jobdate_operate);
                        $('#ticketnoshow').val(rs.data[0].ticket_no);
                        $('#closedateshow').val(rs.data[0].close_date);

                        $('#contactphoneshow').val(rs.data[0].contact_phone);
                        $('#contactemailshow').val(rs.data[0].contact_email);
                        $('#jobnumberhouseshow').val(rs.data[0].job_number_house);
                        $('#convillagenoshow').val(rs.data[0].con_villageno);
                        $('#convillageshow').val(rs.data[0].con_village);
                        $('#joballeyshow').val(rs.data[0].job_alley);
                        $('#jobroadshow').val(rs.data[0].job_road);

                    },'json');   

                    $('#myModalAddJob').modal('hide');
                    $('#job_name').val("");
                    $('#jobstatusshow').val("Open").trigger('change');
                    $('#jobdate').val("");
                    $('#notification_time').val("");
                    $('#jobdate_operate').val("");
                    $('#close_datejob').val("");
                    $('#contact_phonejob').val("");
                    $('#contact_emailjob').val("");
                    $('#job_number_house').val("");
                    $('#con_villagenojob').val("");
                    $('#con_villagejob').val("");
                    $('#job_alleyjob').val("");

                    $("#loader-wrapper").fadeOut('slow');
                } else {
                    swal("", result["Message"], "error");
                    $("#loader-wrapper").fadeOut('slow');
                }
            },
            error: function (data) {
                console.log("error");
                $("#loader-wrapper").fadeOut('slow');
            },
        });
    }

