    function savenote() {

        var url = "<?php echo site_url('omnichannel/create_Documents'); ?>";
        var data = $("#form_save_note").serialize();
        
        var form = $( "#form_save_note" );
        form.validate();

        if (form.valid() == false) {
            return false;
        }
        var crmid = $('#crmid').val();

        $("#loader-wrapper-full").fadeIn('slow');

        $.ajax(url, {
            type: "POST",
