                        var mm = String(d_start.getMonth() + 1).padStart(2, '0'); //January is 0!
                        var yyyy = d_start.getFullYear();
                        
                        var datecreate = mm + '-' + dd + '-' + yyyy;
                        var timecreate = d_start.getHours() + ":" + d_start.getMinutes()+":"+d_start.getSeconds();

                        var cardpreviewnote = '<div class="card"><div class="card-body" style="padding-left: 0px;"><div class="col-sm-12"><div class="row"><div class="col-sm-3" style="text-align: center;"><div class="imgcase bggreen"><img src="<?php echo site_assets_url('images/icons/note-white.png') ?>" style="width: 25px;"></div></div><div class="col-sm-9"><div class="row"><div class="col-sm-12"><div class="row"><div class="col-sm-8 text-left"><span style="color: #A9A9A9;"> '+datecreate+' </span><span style="margin-left: 10px; color: #A9A9A9;"> '+timecreate+' </span></div><div class="col-sm-4" style="text-align: right;"><a href="javascript:void(0)" data-toggle="modal" data-target="#myModalShowNote" class="btnpreview" onclick="previewnote( ' + rs.data[0].notesid + ' )">ดู</a></div></div></div></div><div class="row" style="margin-left: 0px;"><span>' + rs.data[0].title + '</span></div><div class="row" style="margin-left: 0px;"><span style="color: #4455BB; text-decoration: underline;"> ' + rs.data[0].note_no + ' </span></div><div class="row" style="margin-left: 0px;"><span> ' + rs.data[0].filename + ' </span></div> </div></div></div></div></div>';

                        //<div class="row" style="margin-left: 4px;"><img src="<?php //echo site_assets_url('images/icons/user-blue.png') ?>" style="width: 18px; height:18px;">&nbsp; <span style="color: #4454BB; text-decoration: underline;">นางสาวแอน เอไอซิสเต็ม</span></div>
                        $('#cardnote').append(cardpreviewnote);

                        $("#loader-wrapper-full").fadeOut('slow');
                    },'json');  

                    // $('.cardnote').css('display','block');
                    $('#notestitle').val("");
                    $('#notecontent').val("");
                    $('#filenamenote').val("");
                    $('#myModalAddNote').modal('hide');

                    $("#loader-wrapper-full").fadeOut('slow');

