    function saveupdatesalesvisit() {

        var crmid = $('#crmidsalevisit').val();

        if (crmid != null) {

           // console.log(crmidcontact);
           $("#loader-wrapper").fadeIn('slow');

            var url = "<?php echo site_url('omnichannel/update_salevisit'); ?>";
            var data = $('#form_update_salevisit').serialize();

            $.ajax(url, {
                type: "POST",
                data: data + "&crmid=" + crmid,
                success: function (data) {
                    var result = jQuery.parseJSON(data);
                    console.log(result);
                    if (result["Type"] == "S") {
                        
                        swal({
                            position: "center", //'top-end',
                            type: "success",
                            title: result["Message"],
                            showConfirmButton: false,
                            timer: 2000,
                        });
                        $("#loader-wrapper").fadeOut('slow');
                    } else {
                        swal("", result["Message"], "error");
                        $("#loader-wrapper").fadeOut('slow');
                    }
                },
                error: function (data) {
                    console.log("error");
                    $("#loader-wrapper").fadeOut('slow');
                },
            });
        }
    }

    function saveconvert() {

        var crmid =  $('#crmid').val();
        var accountname = $('#dealnamelead').val();
        //var crmid = '55874';
        //var accountname= 'IBass Za Hajuku';
        var url = "<?php echo site_url('omnichannel/convert_lead'); ?>";
        var data = [];
        
        $("#loader-wrapper-full").fadeIn('slow');

        $.ajax(url, {
            type: "POST",
            data: data + "&crmid=" + crmid + "&accountname=" + accountname,
            success: function (data) {
                var result = jQuery.parseJSON(data);
                //console.log(result);
                if (result["Type"] == "S") {
                    $("#loader-wrapper-full").fadeOut('slow');
                    swal({
                        position: "center", //'top-end',
                        type: "success",
                        title: result["Message"],
                        showConfirmButton: false,
                        timer: 2000,
                    });

                    $('.account').css('display','block');
                    $('#leads').css('display','none');
                    //result.data[0].accountid
                    $('#crmid').val(result.data[0].accountid);
                    $('#module').val('Accounts');

                    $('#account_no').val(result.data[0].account_no);
                    $('#accountname').val(result.data[0].accountname);

                    if (result.data[0].corporation == "1") {
                        $('#corporation').prop('checked', true);
                    } else {
                        $('#corporation').prop('checked', false);
                    }

                    if (result.data[0].nametitle == "นาย") {
                        $('#nametitle').val("นาย").trigger('change');
                    } else if (result.data[0].interest == "นาง") {
                        $('#nametitle').val("นาง").trigger('change');
                    } else if (result.data[0].interest == "นางสาว") {
                        $('#nametitle').val("นางสาว").trigger('change');
                    } else {
                        $('#nametitle').val("").trigger('change');
                    }

                    $('#firstnameaccount').val(result.data[0].firstname);
                    $('#lastnameaccount').val(result.data[0].lastname);
                    $('#nicknameaccount').val(result.data[0].nickname);
                    $('#idcardno').val(result.data[0].idcardno);

                    if (result.data[0].type == "ยังไม่เคยซื้อ") {
                        $('#typeaccount').val("ยังไม่เคยซื้อ").trigger('change');
                    } else if (result.data[0].type == "เคยซื้อ") {
                        $('#typeaccount').val("เคยซื้อ").trigger('change');
                    } else {
                        $('#typeaccount').val("").trigger('change');
                    }
                    $('#branchaccount').val(result.data[0].branch).trigger('change');

                    if (result.data[0].blacklist == "1") {
                        $('#blacklistaccount').prop('checked', true);
                    } else {
                        $('#blacklistaccount').prop('checked', false);
                    }

                    $('#careeraccount').val(result.data[0].career);
                    if(result.data[0].birthdate == null){
                        $('#birthdateaccount').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(''));
                    }else{
                       $('#birthdateaccount').datepicker({ dateFormat: 'dd-mm-yy'}).datepicker("setDate", new Date(result.data[0].birthdate)); 
                    }
                    
                    $('#mobileaccount').val(result.data[0].mobile);
                    $('#emailaccount').val(result.data[0].email);
                    $('#faxaccount').val(result.data[0].fax);
                    $('#telaccount').val(result.data[0].tel);
                    $('#taxidaccount').val(result.data[0].taxid);
                    $('#accountdateaccount').val(result.data[0].accountdate);
                    $('#erpaccountidaccount').val(result.data[0].erpaccountid);

                    $('#villageaccount').val(result.data[0].village);
                    $('#addresslineaccount').val(result.data[0].addressline);
                    $('#addressline1account').val(result.data[0].addressline1);
                    $('#villagenoaccount').val(result.data[0].villageno);
                    $('#laneaccount').val(result.data[0].lane);
                    $('#streetaccount').val(result.data[0].street);
                    $('#subdistrictaccount').val(result.data[0].subdistrict);
                    $('#districtaccount').val(result.data[0].district);
                    $('#provinceaccount').val(result.data[0].province);
                    $('#postalcodeaccount').val(result.data[0].postalcode);
                    $('#dscriptionaccount').val(result.data[0].dscription);
                    $('#remarkaccount').val(result.data[0].remark);

                    $('#myModalConvert').modal('hide');

                } else {
                    swal("", result["Message"], "error");
                    $("#loader-wrapper-full").fadeOut('slow');
                }
            },
            error: function (data) {
                console.log("error");
                $("#loader-wrapper-full").fadeOut('slow');
            },
        });

    }

    function saveaccount() {
        var url = "<?php echo site_url('omnichannel/update_account'); ?>";
        var data = $("#form_save_account").serialize();
        var crmid = $("#crmid").val();
        $("#loader-wrapper").fadeIn('slow');
        $.ajax(url, {
            type: "POST",
            //data: data,
            data: data + "&crmid=" + crmid,
            success: function (data) {
                var result = jQuery.parseJSON(data);
                console.log(result);
                if (result["Type"] == "S") {
                    swal({
                            position: "center", //'top-end',
                            type: "success",
                            title: result["Message"],
                            showConfirmButton: false,
                            timer: 2000,
                        });
                    $("#loader-wrapper").fadeOut('slow');
                } else {
                    swal("", result["Message"], "error");
                    $("#loader-wrapper").fadeOut('slow');
                }
            },
            error: function (data) {
                console.log("error");
                $("#loader-wrapper").fadeOut('slow');
            },
        });

    }

</script>

